import { pgTable, text, serial, timestamp, boolean, varchar } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";

// ─── Fatwas ─────────────────────────────────────────────────────────────────

export const fatwaTable = pgTable("fatwas", {
  id: serial("id").primaryKey(),
  question: text("question").notNull(),
  category: varchar("category", { length: 100 }).notNull(),
  answer: text("answer"),
  language: varchar("language", { length: 10 }).notNull().default("auto"),
  source: varchar("source", { length: 200 }),
  isPublic: boolean("is_public").notNull().default(true),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const insertFatwaSchema = createInsertSchema(fatwaTable).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
});
export type InsertFatwa = z.infer<typeof insertFatwaSchema>;
export type Fatwa = typeof fatwaTable.$inferSelect;

// ─── Favorites ───────────────────────────────────────────────────────────────

export const favoritesTable = pgTable("favorites", {
  id: serial("id").primaryKey(),
  deviceId: varchar("device_id", { length: 200 }).notNull(),
  fatwaId: varchar("fatwa_id", { length: 100 }).notNull(),
  question: text("question").notNull(),
  category: varchar("category", { length: 100 }).notNull(),
  answer: text("answer"),
  savedAt: timestamp("saved_at").defaultNow().notNull(),
});

export const insertFavoriteSchema = createInsertSchema(favoritesTable).omit({
  id: true,
  savedAt: true,
});
export type InsertFavorite = z.infer<typeof insertFavoriteSchema>;
export type Favorite = typeof favoritesTable.$inferSelect;
