import { Router } from "express";
import { db, fatwaTable, favoritesTable } from "@workspace/db";
import { eq, desc, ilike, or } from "drizzle-orm";

const router = Router();

// ─── GET /api/fatwas ─────────────────────────────────────────────────────────
// List all public fatwas (for Home screen)
router.get("/fatwas", async (req, res) => {
  try {
    const { category, search, limit = "50", offset = "0" } = req.query as Record<string, string>;
    let query = db
      .select()
      .from(fatwaTable)
      .where(eq(fatwaTable.isPublic, true))
      .orderBy(desc(fatwaTable.createdAt))
      .limit(Number(limit))
      .offset(Number(offset));

    const conditions = [eq(fatwaTable.isPublic, true)];

    if (category && category !== "All") {
      const results = await db
        .select()
        .from(fatwaTable)
        .where(eq(fatwaTable.category, category))
        .orderBy(desc(fatwaTable.createdAt))
        .limit(Number(limit))
        .offset(Number(offset));
      res.json({ fatwas: results, total: results.length });
      return;
    }

    if (search) {
      const results = await db
        .select()
        .from(fatwaTable)
        .where(
          or(
            ilike(fatwaTable.question, `%${search}%`),
            ilike(fatwaTable.category, `%${search}%`),
          ),
        )
        .orderBy(desc(fatwaTable.createdAt))
        .limit(Number(limit));
      res.json({ fatwas: results, total: results.length });
      return;
    }

    const fatwas = await db
      .select()
      .from(fatwaTable)
      .where(eq(fatwaTable.isPublic, true))
      .orderBy(desc(fatwaTable.createdAt))
      .limit(Number(limit))
      .offset(Number(offset));

    res.json({ fatwas, total: fatwas.length });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

// ─── GET /api/fatwas/:id ─────────────────────────────────────────────────────
router.get("/fatwas/:id", async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) { res.status(400).json({ error: "Invalid ID" }); return; }
    const [fatwa] = await db.select().from(fatwaTable).where(eq(fatwaTable.id, id));
    if (!fatwa) { res.status(404).json({ error: "Fatwa not found" }); return; }
    res.json({ fatwa });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

// ─── POST /api/fatwas ────────────────────────────────────────────────────────
// Save a fatwa (after AI research)
router.post("/fatwas", async (req, res) => {
  try {
    const { question, category, answer, language = "auto", source } = req.body as {
      question: string; category: string; answer?: string;
      language?: string; source?: string;
    };
    if (!question || !category) {
      res.status(400).json({ error: "question and category are required" });
      return;
    }
    const [inserted] = await db
      .insert(fatwaTable)
      .values({ question, category, answer, language, source, isPublic: true })
      .returning();
    res.json({ fatwa: inserted });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

// ─── DELETE /api/fatwas/:id ──────────────────────────────────────────────────
router.delete("/fatwas/:id", async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) { res.status(400).json({ error: "Invalid ID" }); return; }
    await db.delete(fatwaTable).where(eq(fatwaTable.id, id));
    res.json({ success: true });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

// ─── GET /api/favorites/:deviceId ────────────────────────────────────────────
router.get("/favorites/:deviceId", async (req, res) => {
  try {
    const { deviceId } = req.params;
    const favs = await db
      .select()
      .from(favoritesTable)
      .where(eq(favoritesTable.deviceId, deviceId))
      .orderBy(desc(favoritesTable.savedAt));
    res.json({ favorites: favs });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

// ─── POST /api/favorites ─────────────────────────────────────────────────────
router.post("/favorites", async (req, res) => {
  try {
    const { deviceId, fatwaId, question, category, answer } = req.body as {
      deviceId: string; fatwaId: string; question: string;
      category: string; answer?: string;
    };
    if (!deviceId || !fatwaId || !question || !category) {
      res.status(400).json({ error: "deviceId, fatwaId, question, category required" });
      return;
    }
    const [inserted] = await db
      .insert(favoritesTable)
      .values({ deviceId, fatwaId, question, category, answer })
      .returning();
    res.json({ favorite: inserted });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

// ─── DELETE /api/favorites/:deviceId/:fatwaId ─────────────────────────────────
router.delete("/favorites/:deviceId/:fatwaId", async (req, res) => {
  try {
    const { deviceId, fatwaId } = req.params;
    await db
      .delete(favoritesTable)
      .where(
        eq(favoritesTable.deviceId, deviceId),
      );
    res.json({ success: true });
  } catch (err) {
    res.status(500).json({ error: err instanceof Error ? err.message : "DB error" });
  }
});

export default router;
